1	// A live cell's coordinates as [x, y]. The grid is unbounded;
2	// coordinates may be negative.
3	export type Cell = [number, number];
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
12	
13	const neighborsOf = ([x, y]: Cell): Cell[] =>
14	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	
16	const countLiveNeighbors = (
17	  cell: Cell,
18	  liveSet: ReadonlySet<string>,
19	): number =>
20	  neighborsOf(cell).filter((neighbor) => liveSet.has(keyOf(neighbor))).length;
21	
22	const survivesToNextGeneration = (liveNeighborCount: number): boolean =>
23	  liveNeighborCount === 2 || liveNeighborCount === 3;
24	
25	const isBornNextGeneration = (liveNeighborCount: number): boolean =>
26	  liveNeighborCount === 3;
27	
28	const uniqueDeadNeighbors = (
29	  liveCells: Cell[],
30	  liveSet: ReadonlySet<string>,
31	): Cell[] => {
32	  const deadNeighbors = new Map<string, Cell>();
33	  for (const cell of liveCells) {
34	    for (const neighbor of neighborsOf(cell)) {
35	      const key = keyOf(neighbor);
36	      if (!liveSet.has(key)) deadNeighbors.set(key, neighbor);
37	    }
38	  }
39	  return [...deadNeighbors.values()];
40	};
41	
42	const cellsMatchingNeighborRule = (
43	  candidates: Cell[],
44	  liveSet: ReadonlySet<string>,
45	  rule: (liveNeighborCount: number) => boolean,
46	): Cell[] =>
47	  candidates.filter((cell) => rule(countLiveNeighbors(cell, liveSet)));
48	
49	export function nextGeneration(liveCells: Cell[]): Cell[] {
50	  const liveSet = new Set(liveCells.map(keyOf));
51	  const deadNeighbors = uniqueDeadNeighbors(liveCells, liveSet);
52	
53	  const survivors = cellsMatchingNeighborRule(liveCells, liveSet, survivesToNextGeneration);
54	  const births = cellsMatchingNeighborRule(deadNeighbors, liveSet, isBornNextGeneration);
55	  return [...survivors, ...births];
56	}
